import React, { useContext } from 'react';
import { useNavigate } from 'react-router-dom';
import { SessionContext } from '../context/SessionContext';
import { WORKFLOW_STAGES, STAGE_CONFIG } from '../workflow/stages';
import RecommendationCard from '../components/job/RecommendationCard';
import AlternativeCard from '../components/job/AlternativeCard';
import { SolverInputCard } from '../components/job/SolverInputCard';
import LoadingSpinner from '../components/common/LoadingSpinner';
import { ArrowRightIcon } from '@heroicons/react/24/solid';

function JobConfiguration() {
  const navigate = useNavigate();
  const { 
    session, 
    artifacts,
    loading, 
    error, 
    updateSession,
    currentStageConfig
  } = useContext(SessionContext);

  const handleSelectAndPrepare = async (solver) => {
    if (!session) return;
    // Update the session to move to the next stage, triggering input preparation
    // The backend function will see the selected solver on the recommendation
    // and prepare the input accordingly.
    await updateSession(session.id, WORKFLOW_STAGES.PREPARE_SOLVER_INPUT, { selectedSolverId: solver.id });
  };

  const handleProceedToExecution = async () => {
    if (session) {
        await updateSession(session.id, WORKFLOW_STAGES.EXECUTE);
        const nextPath = STAGE_CONFIG[WORKFLOW_STAGES.EXECUTE].path;
        navigate(`${nextPath}?session=${session.id}`);
    }
  };

  if (loading && !artifacts.solverInput) return <LoadingSpinner text="Loading or preparing job..." />;
  if (error) return <div className="container mx-auto p-8 text-center text-red-500">{`Error: ${error.message}`}</div>;
  if (!session || !artifacts.recommendation) return <div className="container mx-auto p-8 text-center">Session or recommendation not available.</div>;

  const { recommendation, solverInput } = artifacts;
  const { mappedSolver, alternativeSolver } = recommendation; // Assuming the API populates these

  const renderSelectionStep = () => (
    <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 items-start mb-8">
      {mappedSolver ? (
          <RecommendationCard 
              solver={mappedSolver}
              confidence={recommendation.confidence}
              reasoning={recommendation.reasoningSummary}
              recommendation={recommendation}
              onSelect={() => handleSelectAndPrepare(mappedSolver)}
          />
      ) : <LoadingSpinner text="Loading recommended solver..." />}

      {alternativeSolver ? (
          <AlternativeCard 
              solver={alternativeSolver}
              reasoning={recommendation.classicalFitRationale} 
              onSelect={() => handleSelectAndPrepare(alternativeSolver)}
          />
      ) : <LoadingSpinner text="Loading alternative solver..." />}
    </div>
  );

  const renderReviewStep = () => (
    <div>
      <SolverInputCard contract={solverInput} />
      <div className="mt-8 text-center">
        {solverInput.readinessStatus === 'ready' ? (
          <button 
            onClick={handleProceedToExecution}
            className="bg-indigo-600 text-white font-bold py-3 px-8 rounded-lg hover:bg-indigo-700 transition duration-300 ease-in-out shadow-md flex items-center justify-center mx-auto"
          >
            Proceed to Execution
            <ArrowRightIcon className="h-5 w-5 ml-2" />
          </button>
        ) : (
          <p className="text-gray-600">The input is not ready for execution. Please address the warnings above.</p>
        )}
      </div>
    </div>
  );

  return (
    <div className="container mx-auto p-8">
      <div className="max-w-6xl mx-auto">
        <h1 className="text-4xl font-bold mb-2">AI-Guided Decision Review</h1>
        <p className="text-lg text-gray-600 mb-8">{currentStageConfig?.description}</p>

        {solverInput ? renderReviewStep() : renderSelectionStep()}

      </div>
    </div>
  );
}

export default JobConfiguration;
